CSS:
.aurora-bg {
  background:
    radial-gradient(ellipse 80% 50% at 20% 30%, rgba(139,92,246,0.12) 0%, transparent 50%),
    radial-gradient(ellipse 60% 40% at 80% 20%, rgba(59,130,246,0.1) 0%, transparent 50%),
    radial-gradient(ellipse 60% 40% at 50% 80%, rgba(245,158,11,0.06) 0%, transparent 50%),
    oklch(8% 0.005 160);
}
@keyframes aurora {
  0%, 100% { opacity: 0.6; transform: translate(0, 0) scale(1); }
  33% { opacity: 0.8; transform: translate(2%, -1%) scale(1.02); }
  66% { opacity: 0.7; transform: translate(-1%, 2%) scale(0.98); }
}

